export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [
        {
          rel: "icon",
          type: "image/x-icon",
          href: this.$store.getters.favicon,
        },
      ],
    };
  },
  components: {},
  watchQuery: true,
  async asyncData({ $get }) {
    const { data } = await $get("seckill/seckillTime");
    let swiperIndex = data.findIndex((item) => item.status == 1);
    if (swiperIndex == -1) {
      swiperIndex = data.findIndex((item) => item.status == 0);
    }
    return { timeList:data, swiperIndex };
  },
  data() {
    return {
      page: 1,
      swiperIndex: 0,
      count: 0,
      goodsList: [],
      timeList: [],
      hasData: true,
      swiperOptions: {
        initialSlide: 0,
        pagination: {
          el: ".swiper-pagination",
          clickable: true,
        },
        navigation: {
          nextEl: ".swiper-button-next",
          prevEl: ".swiper-button-prev",
        },
        preventClicks: true,
        slidesPerView: "auto",
      },
    };
  },
  created() {
    this.swiperOptions.initialSlide = this.swiperIndex;
    this.getGoods();
  },
  methods: {
    changeTime(index) {
      this.swiperIndex = index;
      this.getGoods();
      this.page = 1
      this.goodsList = []
    },
    changePage(current) {
      this.page = current;
      this.getGoods();
    },
    async getGoods() {
      const { swiperIndex, timeList, page } = this;
      const id = timeList[swiperIndex] ? timeList[swiperIndex].id : -1
      const {
        data: { list, count },
        code
      } = await this.$get("seckill/seckillGoods", {
        params: {
          page_size: 10,
          page_no: page,
          id,
        },
      });
      if(code == 1) {
        this.goodsList = list;
        this.hasData = !!list.length
        this.count = count;
      }
    },
  },
  computed: {
    status () {
      const {swiperIndex, timeList} = this
      return timeList[swiperIndex] ? timeList[swiperIndex].status : -1
    }
  }
};
